    /**
     * 更新设备状态（对齐 Dart `EhDeviceInfo.updateStatus` 的行为）。
     *
     * 说明：
     * - **原地更新** `this.status`
     * - 仅当 `status.sn === this.sn` 时才会更新
     * - 不一致时直接忽略（不修改）
     */
    updateStatus(status: DeviceStatus): void;
    /** 是否是眼镜 */
    isGlasses(): boolean;
    /** 是否是戒指 */
